from flask import Flask, request, render_template_string, redirect, url_for
from flask_mail import Mail, Message
import secrets
import string
import hashlib
import sqlite3

app = Flask(__name__)
app.config['SECRET_KEY'] = 'secret_key_here'
app.config['MAIL_SERVER'] = 'smtp.gmail.com'
app.config['MAIL_PORT'] = 587
app.config['MAIL_USE_TLS'] = True
app.config['MAIL_USERNAME'] = 'your_email@gmail.com'
app.config['MAIL_PASSWORD'] = 'your_password'

mail = Mail(app)

# SQLite DB setup
conn = sqlite3.connect('users.db')
c = conn.cursor()

c.execute('''CREATE TABLE IF NOT EXISTS users
             (id INTEGER PRIMARY KEY AUTOINCREMENT, email text UNIQUE, mfa_enabled integer)''')

conn.commit()
conn.close()

def generate_secret():
    return ''.join(secrets.choice(string.ascii_letters + string.digits) for _ in range(16))

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    email = request.form['email']
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute("SELECT * FROM users WHERE email=?", (email,))
    user = c.fetchone()
    if user:
        secret = generate_secret()
        hashed_email = hashlib.sha256(email.encode()).hexdigest()
        conn = sqlite3.connect('users.db')
        c = conn.cursor()
        c.execute("UPDATE users SET mfa_enabled=1, mfa_secret=? WHERE email=?", (hashed_email, email))
        conn.commit()
        conn.close()
        msg = Message('MFA Enabled', sender='your_email@gmail.com', recipients=[email])
        msg.body = f'Your MFA secret is: {secret}'
        mail.send(msg)
    return 'MFA enabled'

@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    email = request.form['email']
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute("SELECT * FROM users WHERE email=?", (email,))
    user = c.fetchone()
    if user:
        hashed_email = hashlib.sha256(email.encode()).hexdigest()
        conn = sqlite3.connect('users.db')
        c = conn.cursor()
        c.execute("UPDATE users SET mfa_enabled=0, mfa_secret=? WHERE email=?", (hashed_email, email))
        conn.commit()
        conn.close()
    return 'MFA disabled'

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    email = request.form['email']
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute("SELECT * FROM users WHERE email=?", (email,))
    user = c.fetchone()
    if user:
        hashed_email = hashlib.sha256(email.encode()).hexdigest()
        secret = generate_secret()
        conn = sqlite3.connect('users.db')
        c = conn.cursor()
        c.execute("UPDATE users SET mfa_enabled=0, mfa_secret=? WHERE email=?", (hashed_email, email))
        conn.commit()
        conn.close()
        msg = Message('Reset MFA Link', sender='your_email@gmail.com', recipients=[email])
        msg.body = f'Click this link to reset your MFA: http://localhost:5000/reset-mfa/{secret}'
        mail.send(msg)
    return 'MFA reset link sent'

@app.route('/reset-mfa/<string:secret>', methods=['GET'])
def reset_mfa_link(secret):
    hashed_email = hashlib.sha256(request.args.get('email').encode()).hexdigest()
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute("SELECT * FROM users WHERE mfa_secret=? AND email=?", (hashed_email, request.args.get('email')))
    user = c.fetchone()
    if user:
        hashed_email = hashlib.sha256(request.args.get('email').encode()).hexdigest()
        conn = sqlite3.connect('users.db')
        c = conn.cursor()
        c.execute("UPDATE users SET mfa_enabled=0, mfa_secret=? WHERE email=?", (hashed_email, request.args.get('email')))
        conn.commit()
        conn.close()
    return 'MFA reset'

